import{_ as o,C as n,o as l,c as s,E as i,w as a,a as r,a0 as d}from"./chunks/framework.CkNTPv-z.js";const p=JSON.parse('{"title":"Moving to Italy","description":"Immigration pathways and relocation guide for Italy","frontmatter":{"layout":"doc","title":"Moving to Italy","description":"Immigration pathways and relocation guide for Italy"},"headers":[],"relativePath":"europe/italy/moving-there.md","filePath":"europe/italy/moving-there.md","lastUpdated":null}'),g={name:"europe/italy/moving-there.md"};function h(c,t,u,m,f,y){const e=n("Badge");return l(),s("div",null,[i(e,{variant:"green"},{default:a(()=>[...t[0]||(t[0]=[r("EU: Free Movement",-1)])]),_:1}),i(e,{variant:"yellow"},{default:a(()=>[...t[1]||(t[1]=[r("Non-EU: Elective Residence Visa",-1)])]),_:1}),i(e,{variant:"yellow"},{default:a(()=>[...t[2]||(t[2]=[r("No Specific DN Visa",-1)])]),_:1}),t[3]||(t[3]=d('<h1 id="moving-to-italy" tabindex="-1">Moving to Italy <a class="header-anchor" href="#moving-to-italy" aria-label="Permalink to &quot;Moving to Italy&quot;">​</a></h1><h2 id="immigration-pathways" tabindex="-1">Immigration Pathways <a class="header-anchor" href="#immigration-pathways" aria-label="Permalink to &quot;Immigration Pathways&quot;">​</a></h2><h3 id="eea-eu-citizens" tabindex="-1">EEA/EU Citizens <a class="header-anchor" href="#eea-eu-citizens" aria-label="Permalink to &quot;EEA/EU Citizens&quot;">​</a></h3><ul><li><strong>Free movement rights</strong> — no visa required</li><li><strong>Up to 3 months</strong>: No formalities</li><li><strong>Over 3 months</strong>: Register with the Anagrafe (municipal registry) and obtain a Codice Fiscale (tax code)</li><li><strong>Right to work</strong>: Automatic, no work permit needed</li><li><strong>Residenza</strong>: Official residence status after registration</li></ul><h3 id="uk-citizens-post-brexit" tabindex="-1">UK Citizens (Post-Brexit) <a class="header-anchor" href="#uk-citizens-post-brexit" aria-label="Permalink to &quot;UK Citizens (Post-Brexit)&quot;">​</a></h3><ul><li><strong>Schengen Area</strong>: Visa-free for up to 90 days in any 180-day period</li><li><strong>Longer stays</strong>: Apply for residence permit: <ul><li><strong>Work visa</strong>: Job offer from Italian employer</li><li><strong>Elective Residence Visa</strong>: Proof of sufficient passive income (€31,000+/year)</li><li><strong>Student Visa</strong>: Enrollment at Italian university</li><li><strong>Family Reunification</strong>: Family ties to Italian resident</li><li><strong>Golden Visa</strong>: Investment of €500,000+ (bonds) or €250,000+ (start-up)</li></ul></li></ul><h3 id="third-country-nationals" tabindex="-1">Third-Country Nationals <a class="header-anchor" href="#third-country-nationals" aria-label="Permalink to &quot;Third-Country Nationals&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Visa Type</th><th>Requirements</th><th>Duration</th></tr></thead><tbody><tr><td>Work Visa (Subordinato)</td><td>Job offer from Italian employer</td><td>1-2 years, renewable</td></tr><tr><td>Elective Residence Visa</td><td>Sufficient passive income (~€31,000/year)</td><td>1 year, renewable</td></tr><tr><td>Student Visa</td><td>Enrollment at accredited institution</td><td>Duration of studies</td></tr><tr><td>Family Reunification</td><td>Family ties to Italian resident</td><td>Tied to sponsor&#39;s status</td></tr><tr><td>Golden Visa</td><td>Investment (€250k-€500k+)</td><td>2 years, renewable</td></tr><tr><td>EU Blue Card</td><td>Highly skilled (salary ~€30,000+/year)</td><td>Up to 4 years</td></tr></tbody></table><h2 id="digital-nomad-remote-work" tabindex="-1">Digital Nomad / Remote Work <a class="header-anchor" href="#digital-nomad-remote-work" aria-label="Permalink to &quot;Digital Nomad / Remote Work&quot;">​</a></h2><p>Italy does <strong>not have a dedicated digital nomad visa</strong>. Remote workers typically use:</p><ul><li><strong>Elective Residence Visa</strong>: For those with passive income (pensioners, investors, remote workers with high savings) <ul><li>Minimum income: ~€31,000/year (varies by consulate)</li><li>Does NOT allow work for Italian companies</li><li>Valid for 1 year, renewable</li><li>Can transition to permanent residency after 5 years</li></ul></li><li><strong>Work Visa</strong>: If employed by an Italian company</li><li><strong>Freelance Visa (Lavoro Autonomo)</strong>: For self-employed professionals, requires a business plan and client base</li></ul><h2 id="moving-checklist" tabindex="-1">Moving Checklist <a class="header-anchor" href="#moving-checklist" aria-label="Permalink to &quot;Moving Checklist&quot;">​</a></h2><h3 id="before-moving" tabindex="-1">Before Moving <a class="header-anchor" href="#before-moving" aria-label="Permalink to &quot;Before Moving&quot;">​</a></h3><ul><li>[ ] <strong>Passport</strong>: Valid for duration of stay</li><li>[ ] <strong>Visa</strong>: Apply 2-4 months in advance at Italian consulate</li><li>[ ] <strong>Healthcare</strong>: Private health insurance required for visa; register with SSN after residency</li><li>[ ] <strong>HRT</strong>: Get 3-6 month supply and doctor&#39;s letter (translated to Italian)</li><li>[ ] <strong>Banking</strong>: Consider Intesa Sanpaolo, UniCredit, or Fineco</li><li>[ ] <strong>Housing</strong>: Research rental market (immobiliare.it, idealista.it)</li><li>[ ] <strong>Language</strong>: Italian essential for bureaucracy and daily life</li><li>[ ] <strong>Document translation</strong>: Apostille and official translations of key documents</li></ul><h3 id="after-arrival" tabindex="-1">After Arrival <a class="header-anchor" href="#after-arrival" aria-label="Permalink to &quot;After Arrival&quot;">​</a></h3><ul><li>[ ] Apply for Permesso di Soggiorno (residence permit) — non-EU</li><li>[ ] Register with Anagrafe (municipal registry)</li><li>[ ] Obtain Codice Fiscale (tax code) — essential for everything</li><li>[ ] Register with SSN (Servizio Sanitario Nazionale) for healthcare</li><li>[ ] Open local bank account</li><li>[ ] Get local SIM card (TIM, Vodafone, WindTre, Iliad)</li><li>[ ] Find a GP (Medico di Base) for referrals</li><li>[ ] Connect with LGBTQ+ organizations (MIT, Arcigay)</li><li>[ ] Locate the nearest gender clinic (Careggi Florence, San Camillo Rome)</li></ul><h2 id="practical-information" tabindex="-1">Practical Information <a class="header-anchor" href="#practical-information" aria-label="Permalink to &quot;Practical Information&quot;">​</a></h2><h3 id="cost-of-living" tabindex="-1">Cost of Living <a class="header-anchor" href="#cost-of-living" aria-label="Permalink to &quot;Cost of Living&quot;">​</a></h3><ul><li><strong>Moderate</strong> — varies significantly by region</li><li>Monthly rent (1-bed): <ul><li>Milan: €800-1,400</li><li>Rome: €600-1,000</li><li>Florence/Bologna: €600-900</li><li>Naples/South: €400-700</li></ul></li><li>Monthly groceries: €250-400</li><li>Public transport: €35-50/month</li></ul><h3 id="best-cities-for-lgbtq-community" tabindex="-1">Best Cities for LGBTQ+ Community <a class="header-anchor" href="#best-cities-for-lgbtq-community" aria-label="Permalink to &quot;Best Cities for LGBTQ+ Community&quot;">​</a></h3><table tabindex="0"><thead><tr><th>City</th><th>LGBTQ+ Scene</th><th>Trans Healthcare</th></tr></thead><tbody><tr><td><strong>Bologna</strong></td><td>Excellent</td><td>Good (Sant&#39;Orsola)</td></tr><tr><td><strong>Milan</strong></td><td>Excellent</td><td>Good (San Raffaele)</td></tr><tr><td><strong>Florence</strong></td><td>Very Good</td><td>Best (Careggi)</td></tr><tr><td><strong>Rome</strong></td><td>Good</td><td>Good (San Camillo)</td></tr><tr><td><strong>Naples</strong></td><td>Moderate</td><td>Limited</td></tr><tr><td><strong>Palermo</strong></td><td>Moderate</td><td>Limited</td></tr></tbody></table><h3 id="climate" tabindex="-1">Climate <a class="header-anchor" href="#climate" aria-label="Permalink to &quot;Climate&quot;">​</a></h3><ul><li><strong>North</strong>: Cold winters (0-10°C), warm summers (20-30°C)</li><li><strong>Central</strong>: Mild winters (5-15°C), hot summers (25-35°C)</li><li><strong>South/Islands</strong>: Mild winters (10-20°C), very hot summers (30-40°C)</li></ul><h3 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h3><ul><li>Official language: Italian</li><li>English: Limited outside tourist areas and tech industry</li><li>Italian essential for bureaucracy, healthcare, and daily life</li><li>Free Italian language courses available through CPIA (Centri Provinciali Istruzione Adulti)</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.esteri.it/" target="_blank" rel="noreferrer">Italian Ministry of Foreign Affairs</a></li><li><a href="https://www.interno.gov.it/" target="_blank" rel="noreferrer">Italian Ministry of the Interior (Immigration)</a></li><li><a href="https://www.salute.gov.it/" target="_blank" rel="noreferrer">SSN (National Health Service)</a></li><li><a href="https://www.mit-italia.it/" target="_blank" rel="noreferrer">MIT (Movimento Identità Trans)</a></li><li><a href="https://www.arcigay.it/" target="_blank" rel="noreferrer">Arcigay</a></li><li><a href="https://www.idealista.it/" target="_blank" rel="noreferrer">Idealista (housing)</a></li></ul>',27))])}const v=o(g,[["render",h]]);export{p as __pageData,v as default};
